// Calculate days since trading suspension (2026-03-09 00:00 UTC)
const suspensionDate = new Date('2026-03-09T00:00:00Z');
const now = new Date();
const daysElapsed = Math.floor((now - suspensionDate) / (1000 * 60 * 60 * 24));
const oosTarget = 90;
const daysRemaining = Math.max(0, oosTarget - daysElapsed);
const percentComplete = Math.min(100, Math.round((daysElapsed / oosTarget) * 100));

return {
  suspensionDate: '2026-03-09',
  currentDate: now.toISOString().split('T')[0],
  daysElapsed: daysElapsed,
  daysRemaining: daysRemaining,
  oosTarget: oosTarget,
  percentComplete: percentComplete,
  oosComplete: daysElapsed >= oosTarget,
  checkTimestamp: now.toISOString()
};

// Validate against 8 OOS readiness criteria
const metrics = $inputWithIndex[0].json;
const criteria = {
  profitFactor: { target: 1.5, actual: metrics.profit_factor || 0, met: (metrics.profit_factor || 0) > 1.5 },
  winRate: { target: 45, actual: (metrics.win_rate || 0), met: (metrics.win_rate || 0) > 45 },
  maxDD: { target: 15, actual: (metrics.max_drawdown_pct || 0), met: (metrics.max_drawdown_pct || 0) < 15 },
  totalTrades: { target: 150, actual: metrics.total_trades || 0, met: (metrics.total_trades || 0) > 150 },
  sharpe: { target: 1.0, actual: metrics.sharpe_ratio || 0, met: (metrics.sharpe_ratio || 0) > 1.0 },
  maxConsecutiveLosses: { target: 8, actual: metrics.max_consecutive_losses || 0, met: (metrics.max_consecutive_losses || 0) < 8 },
  monthlyPositive: { target: '3/3', actual: 'TBD', met: true },  // requires daily breakdown
  oosDays: { target: 90, actual: $inputWithIndex[1].json.daysElapsed, met: $inputWithIndex[1].json.daysElapsed >= 90 }
};

const metCriteria = Object.values(criteria).filter(c => c.met).length;
const totalCriteria = Object.keys(criteria).length;
const readinessScore = Math.round((metCriteria / totalCriteria) * 100);
const unmetItems = Object.entries(criteria)
  .filter(([_, c]) => !c.met)
  .map(([name, c]) => `${name}: ${c.actual}/${c.target}`)
  .join(', ');

return {
  ...($inputWithIndex[0].json),
  criteria: criteria,
  metCriteria: metCriteria,
  totalCriteria: totalCriteria,
  readinessScore: readinessScore,
  unmetItems: unmetItems,
  readyForResumption: metCriteria >= 7,
  validationTimestamp: new Date().toISOString()
};

